package com.example.cbt

import android.os.Bundle
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import android.widget.ImageView
import android.widget.TextView
import android.widget.LinearLayout

class DetailResultActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_detail_ujian)

        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.activity_detail_ujian)) { v, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            v.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        // Get data dari intent
        val subject = intent.getStringExtra("subject") ?: "Matematika"
        val score = intent.getStringExtra("score") ?: "0%"
        val date = intent.getStringExtra("date") ?: "N/A"
        val duration = intent.getStringExtra("duration") ?: "0 Menit"
        val isPassed = intent.getBooleanExtra("isPassed", false)

        // Set data ke views
        findViewById<TextView>(R.id.activity_detail_ujian).apply {
            // Placeholder - gunakan view yang tepat
        }

        // Update judul subject di bagian atas
        val titleViews = this.window.decorView.rootView.findViewsWithText(
            android.widget.LinearLayout::class.java, 
            subject, 
            android.view.View.FIND_VIEWS_WITH_TEXT
        )

        // Set subject name di header
        val headerLayout = findViewById<LinearLayout>(R.id.stats_card)
        headerLayout?.let {
            val tvSubjectName = it.findViewWithTag<TextView>("subject_name")
            tvSubjectName?.text = subject
        }

        // Update score display
        val scoreText = score.replace("%", "")

        // Set status berdasarkan score
        val statusText = if (isPassed) "LULUS" else "TIDAK LULUS"

        // Back button
        findViewById<ImageView>(R.id.btn_back).setOnClickListener {
            finish()
        }

        // Hide atau modify elements yang tidak perlu untuk hasil ujian
        findViewById<LinearLayout>(R.id.stats_card)?.visibility = android.view.View.VISIBLE
    }
}
